"use client";

import { useEffect, useRef, useState } from "react";

import { getMe, login, type AuthUser } from "../../auth/api/auth";
import {
  createConversation,
  listAssistantConversations,
  listConversationMessages,
  sendConversationMessage,
  streamConversationMessage,
} from "../api/chat";
import type {
  AssistantConversation,
  AssistantMessage,
  AssistantPresence,
  AssistantResponseMode,
} from "../types/chat";
import { ApiRequestError } from "../../../lib/api/http";
import { APP_EVENTS, STORAGE_KEYS } from "../../../lib/constants/api";

type LoginForm = {
  identifier: string;
  password: string;
};

const DEFAULT_LOGIN_FORM: LoginForm = {
  identifier: "",
  password: "",
};

function readStoredUser() {
  if (typeof window === "undefined") {
    return null;
  }

  const raw = window.localStorage.getItem(STORAGE_KEYS.currentUser);
  if (!raw) {
    return null;
  }

  try {
    return JSON.parse(raw) as AuthUser;
  } catch {
    return null;
  }
}

function buildUserMessage(
  conversationId: string,
  content: string,
): AssistantMessage {
  return {
    id: `local-user-${Date.now()}`,
    conversation_id: conversationId,
    role: "user",
    content,
    audio_url: null,
    duration_ms: null,
    created_at: new Date().toISOString(),
  };
}

async function playAudio(url: string) {
  const audio = new Audio(url);
  audio.preload = "auto";

  await new Promise<void>((resolve, reject) => {
    const cleanup = () => {
      audio.onended = null;
      audio.onerror = null;
    };

    audio.onended = () => {
      cleanup();
      resolve();
    };

    audio.onerror = () => {
      cleanup();
      reject(new Error("Audio playback failed"));
    };

    void audio.play().catch((error) => {
      cleanup();
      reject(error);
    });
  });
}

export function useAssistantChat() {
  const [token, setToken] = useState<string | null>(null);
  const [currentUser, setCurrentUser] = useState<AuthUser | null>(null);
  const [conversations, setConversations] = useState<AssistantConversation[]>([]);
  const [activeConversationId, setActiveConversationId] = useState<string | null>(
    null,
  );
  const [messages, setMessages] = useState<AssistantMessage[]>([]);
  const [messageDraft, setMessageDraft] = useState("");
  const [avatarDraft, setAvatarDraft] = useState("");
  const [presence, setPresence] = useState<AssistantPresence>("offline");
  const [isBootstrapping, setIsBootstrapping] = useState(true);
  const [isLoggingIn, setIsLoggingIn] = useState(false);
  const [isSending, setIsSending] = useState(false);
  const [isDrawerOpen, setIsDrawerOpen] = useState(false);
  const [errorMessage, setErrorMessage] = useState<string | null>(null);
  const [loginForm, setLoginForm] = useState<LoginForm>(DEFAULT_LOGIN_FORM);
  const audioRunIdRef = useRef(0);

  const persistSession = (nextToken: string, nextUser: AuthUser) => {
    window.localStorage.setItem(STORAGE_KEYS.accessToken, nextToken);
    window.localStorage.setItem(
      STORAGE_KEYS.currentUser,
      JSON.stringify(nextUser),
    );
    setToken(nextToken);
    setCurrentUser(nextUser);
    window.dispatchEvent(new Event(APP_EVENTS.sessionChanged));
  };

  const clearSession = () => {
    window.localStorage.removeItem(STORAGE_KEYS.accessToken);
    window.localStorage.removeItem(STORAGE_KEYS.refreshToken);
    window.localStorage.removeItem(STORAGE_KEYS.currentUser);
    setToken(null);
    setCurrentUser(null);
    setConversations([]);
    setActiveConversationId(null);
    setMessages([]);
    setPresence("offline");
    window.dispatchEvent(new Event(APP_EVENTS.sessionChanged));
  };

  const loadConversationMessages = async (
    nextToken: string,
    conversationId: string,
  ) => {
    const data = await listConversationMessages(nextToken, conversationId);
    setMessages(data.items);
    setActiveConversationId(conversationId);
  };

  const ensureConversation = async (nextToken: string) => {
    const conversationList = await listAssistantConversations(nextToken);
    const items = conversationList.items;
    setConversations(items);

    if (items.length > 0) {
      await loadConversationMessages(nextToken, items[0].id);
      return items[0].id;
    }

    const createdConversation = await createConversation(nextToken);
    setConversations([createdConversation]);
    setMessages([]);
    setActiveConversationId(createdConversation.id);
    return createdConversation.id;
  };

  const bootstrapWithToken = async (nextToken: string) => {
    setIsBootstrapping(true);
    setErrorMessage(null);

    try {
      const me = await getMe(nextToken);
      persistSession(nextToken, me);
      await ensureConversation(nextToken);
      setPresence("idle");
    } catch (error) {
      clearSession();
      setErrorMessage(
        error instanceof Error
          ? error.message
          : "Assistant workspace bootstrap failed",
      );
    } finally {
      setIsBootstrapping(false);
    }
  };

  useEffect(() => {
    if (typeof window === "undefined") {
      return;
    }

    const savedToken = window.localStorage.getItem(STORAGE_KEYS.accessToken);
    const savedUser = readStoredUser();

    if (!savedToken) {
      setCurrentUser(savedUser);
      setIsBootstrapping(false);
      return;
    }

    if (savedUser) {
      setCurrentUser(savedUser);
    }

    void bootstrapWithToken(savedToken);
  }, []);

  useEffect(() => {
    const syncSessionState = () => {
      const savedToken = window.localStorage.getItem(STORAGE_KEYS.accessToken);
      const savedUser = readStoredUser();

      if (!savedToken || !savedUser) {
        setToken(null);
        setCurrentUser(null);
        setConversations([]);
        setActiveConversationId(null);
        setMessages([]);
        setPresence("offline");
      }
    };

    window.addEventListener(APP_EVENTS.sessionChanged, syncSessionState);

    return () => {
      window.removeEventListener(APP_EVENTS.sessionChanged, syncSessionState);
    };
  }, []);

  const handleLoginSubmit = async () => {
    if (!loginForm.identifier.trim() || !loginForm.password.trim()) {
      setErrorMessage("Enter username or email, then password");
      return;
    }

    setIsLoggingIn(true);
    setErrorMessage(null);

    try {
      const result = await login({
        identifier: loginForm.identifier.trim(),
        password: loginForm.password,
        remember_me: true,
      });

      window.localStorage.setItem(
        STORAGE_KEYS.refreshToken,
        result.token.refresh_token,
      );

      persistSession(result.token.access_token, result.user);
      await ensureConversation(result.token.access_token);
      setPresence("idle");
      setLoginForm(DEFAULT_LOGIN_FORM);
    } catch (error) {
      setPresence("error");
      setErrorMessage(
        error instanceof Error ? error.message : "Login failed, check the backend",
      );
    } finally {
      setIsLoggingIn(false);
      setIsBootstrapping(false);
    }
  };

  const handleConversationSelect = async (conversationId: string) => {
    if (!token || conversationId === activeConversationId) {
      return;
    }

    setErrorMessage(null);

    try {
      await loadConversationMessages(token, conversationId);
      setPresence("idle");
    } catch (error) {
      setPresence("error");
      setErrorMessage(
        error instanceof Error
          ? error.message
          : "Failed to load conversation messages",
      );
    }
  };

  const handleCreateConversation = async () => {
    if (!token) {
      setErrorMessage("Log in before creating a new conversation");
      return;
    }

    setErrorMessage(null);

    try {
      const createdConversation = await createConversation(token);
      setConversations((current) => [createdConversation, ...current]);
      setActiveConversationId(createdConversation.id);
      setMessages([]);
      setPresence("idle");
    } catch (error) {
      setPresence("error");
      setErrorMessage(
        error instanceof Error ? error.message : "Failed to create conversation",
      );
    }
  };

  const sendMessage = async (
    draft: string,
    responseMode: AssistantResponseMode,
    clearDraft: () => void,
  ) => {
    if (!token) {
      setErrorMessage("Log in before sending a message");
      return;
    }

    const content = draft.trim();
    if (!content || isSending) {
      return;
    }

    setIsSending(true);
    setErrorMessage(null);
    setPresence("thinking");

    try {
      const conversationId =
        activeConversationId || (await ensureConversation(token));
      const userMessage = buildUserMessage(conversationId, content);
      const pendingAssistantId = `local-assistant-${Date.now()}`;
      const pendingAssistantMessage: AssistantMessage = {
        id: pendingAssistantId,
        conversation_id: conversationId,
        role: "assistant",
        content: "",
        audio_url: null,
        duration_ms: null,
        created_at: new Date().toISOString(),
      };

      setMessages((current) => [
        ...current,
        userMessage,
        pendingAssistantMessage,
      ]);
      clearDraft();

      if (responseMode === "text") {
        await streamConversationMessage(token, conversationId, content, {
          onDelta: ({ content: delta }) => {
            setMessages((current) =>
              current.map((message) =>
                message.id === pendingAssistantId
                  ? {
                      ...message,
                      content: `${message.content}${delta}`,
                    }
                  : message,
              ),
            );
          },
          onEnd: (reply) => {
            setMessages((current) =>
              current.map((message) =>
                message.id === pendingAssistantId
                  ? {
                      id: reply.message_id,
                      conversation_id: conversationId,
                      role: "assistant",
                      content: reply.content,
                      audio_url: reply.audio_url,
                      duration_ms: reply.duration_ms,
                      created_at: reply.created_at,
                    }
                  : message,
              ),
            );
          },
          onError: ({ message }) => {
            setErrorMessage(message);
          },
        });
      } else {
        const reply = await sendConversationMessage(
          token,
          conversationId,
          content,
          responseMode,
        );
        const assistantMessage: AssistantMessage = {
          id: reply.message_id,
          conversation_id: conversationId,
          role: "assistant",
          content: reply.content,
          audio_url: reply.audio_url,
          duration_ms: reply.duration_ms,
          created_at: reply.created_at,
        };

        setMessages((current) =>
          current.map((message) =>
            message.id === pendingAssistantId ? assistantMessage : message,
          ),
        );

        if (assistantMessage.audio_url && responseMode === "voice") {
          const runId = Date.now();
          audioRunIdRef.current = runId;
          setPresence("speaking");

          try {
            await playAudio(assistantMessage.audio_url);
            if (audioRunIdRef.current === runId) {
              setPresence("idle");
            }
          } catch {
            setPresence("idle");
          }
        }
      }

      const refreshedConversations = await listAssistantConversations(token);
      setConversations(refreshedConversations.items);
      setActiveConversationId(conversationId);

      setPresence("idle");
    } catch (error) {
      setPresence("error");
      if (error instanceof ApiRequestError && error.status === 401) {
        clearSession();
      }
      if (responseMode === "text") {
        setMessages((current) =>
          current.filter((message) => !message.id.startsWith("local-assistant-")),
        );
      } else {
        setMessages((current) =>
          current.filter((message) => message.id !== pendingAssistantId),
        );
      }
      setErrorMessage(
        error instanceof Error ? error.message : "Failed to send message",
      );
    } finally {
      setIsSending(false);
    }
  };

  const handleSendMessage = async () => {
    await sendMessage(messageDraft, "text", () => setMessageDraft(""));
  };

  const handleSendAvatarMessage = async () => {
    await sendMessage(avatarDraft, "voice", () => setAvatarDraft(""));
  };

  const handleLogout = () => {
    clearSession();
    setLoginForm(DEFAULT_LOGIN_FORM);
    setErrorMessage(null);
  };

  return {
    token,
    currentUser,
    conversations,
    activeConversationId,
    messages,
    messageDraft,
    setMessageDraft,
    avatarDraft,
    setAvatarDraft,
    presence,
    isBootstrapping,
    isLoggingIn,
    isSending,
    isDrawerOpen,
    setIsDrawerOpen,
    errorMessage,
    loginForm,
    setLoginForm,
    handleLoginSubmit,
    handleConversationSelect,
    handleCreateConversation,
    handleSendMessage,
    handleSendAvatarMessage,
    handleLogout,
  };
}
