"use client";

import { useEffect, useMemo, useRef, useState } from "react";

import { useAssistantChat } from "../hooks/use-assistant-chat";
import { Live2DAvatar } from "./live2d-avatar";

const PRESENCE_LABEL: Record<string, string> = {
  offline: "Offline",
  idle: "Idle",
  thinking: "Thinking",
  speaking: "Speaking",
  error: "Error",
};

function formatTime(value: string) {
  const date = new Date(value);

  if (Number.isNaN(date.getTime())) {
    return "--";
  }

  return new Intl.DateTimeFormat("zh-CN", {
    month: "2-digit",
    day: "2-digit",
    hour: "2-digit",
    minute: "2-digit",
  }).format(date);
}

export function AssistantWorkspace() {
  const audioRef = useRef<HTMLAudioElement | null>(null);
  const [playingAudioUrl, setPlayingAudioUrl] = useState<string | null>(null);

  const {
    token,
    currentUser,
    conversations,
    activeConversationId,
    messages,
    messageDraft,
    setMessageDraft,
    avatarDraft,
    setAvatarDraft,
    presence,
    isBootstrapping,
    isLoggingIn,
    isSending,
    isDrawerOpen,
    setIsDrawerOpen,
    errorMessage,
    loginForm,
    setLoginForm,
    handleLoginSubmit,
    handleConversationSelect,
    handleCreateConversation,
    handleSendMessage,
    handleSendAvatarMessage,
  } = useAssistantChat();

  const statusText = useMemo(
    () => PRESENCE_LABEL[presence] ?? "Idle",
    [presence],
  );

  const recentAvatarMessages = useMemo(() => messages.slice(-4), [messages]);

  const learnerName =
    currentUser?.full_name || currentUser?.username || "Learner";

  useEffect(() => {
    return () => {
      if (audioRef.current) {
        audioRef.current.pause();
        audioRef.current = null;
      }
    };
  }, []);

  const handleAudioToggle = async (audioUrl: string) => {
    if (audioRef.current && playingAudioUrl === audioUrl) {
      audioRef.current.pause();
      audioRef.current = null;
      setPlayingAudioUrl(null);
      return;
    }

    if (audioRef.current) {
      audioRef.current.pause();
      audioRef.current = null;
    }

    const audio = new Audio(audioUrl);
    audio.preload = "auto";
    audio.onended = () => {
      setPlayingAudioUrl(null);
      audioRef.current = null;
    };
    audio.onerror = () => {
      setPlayingAudioUrl(null);
      audioRef.current = null;
    };

    audioRef.current = audio;
    setPlayingAudioUrl(audioUrl);

    try {
      await audio.play();
    } catch {
      setPlayingAudioUrl(null);
      audioRef.current = null;
    }
  };

  return (
    <section className="assistant-shell">
      <div className="assistant-layout">
        <aside className="assistant-history">
          <div className="assistant-section-head">
            <div>
              <div className="eyebrow">Assistant Console</div>
              <h3 className="section-title">Conversation History</h3>
            </div>
          </div>

          <div className="assistant-login-card">
            {token && currentUser ? (
              <>
                <div className="assistant-login-copy">
                  <div className="assistant-user-name">New Conversation</div>
                  <div className="assistant-user-meta">
                    Start a fresh question thread for the current chapter.
                  </div>
                </div>

                <button
                  className="button-primary assistant-full-button"
                  type="button"
                  onClick={handleCreateConversation}
                >
                  Create Conversation
                </button>
              </>
            ) : (
              <>
                <div className="assistant-login-copy">
                  <div className="assistant-user-name">Connect Backend</div>
                  <div className="assistant-user-meta">
                    Sign in here to fetch a token and load conversations.
                  </div>
                </div>

                <div className="assistant-login-form">
                  <label className="field-group">
                    <span className="field-label">Username or Email</span>
                    <input
                      className="field-input"
                      type="text"
                      value={loginForm.identifier}
                      onChange={(event) =>
                        setLoginForm((current) => ({
                          ...current,
                          identifier: event.target.value,
                        }))
                      }
                      placeholder="Enter identifier"
                    />
                  </label>

                  <label className="field-group">
                    <span className="field-label">Password</span>
                    <input
                      className="field-input"
                      type="password"
                      value={loginForm.password}
                      onChange={(event) =>
                        setLoginForm((current) => ({
                          ...current,
                          password: event.target.value,
                        }))
                      }
                      placeholder="Enter password"
                    />
                  </label>

                  <button
                    className="button-primary assistant-full-button"
                    type="button"
                    onClick={handleLoginSubmit}
                    disabled={isLoggingIn}
                  >
                    {isLoggingIn ? "Signing in..." : "Connect Backend"}
                  </button>
                </div>
              </>
            )}
          </div>

          <div className="assistant-conversation-list">
            {conversations.length === 0 ? (
              <div className="assistant-empty-card">
                {isBootstrapping
                  ? "Bootstrapping conversations..."
                  : "No conversations yet"}
              </div>
            ) : (
              conversations.map((conversation, index) => (
                <button
                  key={conversation.id}
                  className={`assistant-conversation-item${
                    conversation.id === activeConversationId ? " is-active" : ""
                  }`}
                  type="button"
                  onClick={() => handleConversationSelect(conversation.id)}
                >
                  <div className="assistant-conversation-title">
                    Conversation {String(index + 1).padStart(2, "0")}
                  </div>
                  <div className="assistant-conversation-meta">
                    {formatTime(conversation.updated_at)}
                  </div>
                  <div className="assistant-conversation-id">{conversation.id}</div>
                </button>
              ))
            )}
          </div>
        </aside>

        <div className="assistant-main">
          {errorMessage ? (
            <div className="assistant-error-banner">{errorMessage}</div>
          ) : null}

          <div className="assistant-chat-panel">
            <div className="assistant-chat-scroll">
              {messages.length === 0 ? (
                <div className="assistant-empty-chat">
                  {token
                    ? "Ask about the current chapter to start the conversation."
                    : "Connect a backend account from the left side first."}
                </div>
              ) : (
                messages.map((message) => {
                  const isAssistant = message.role === "assistant";
                  const speakerName = isAssistant ? "AI Tutor" : learnerName;

                  return (
                    <article
                      key={message.id}
                      className={`assistant-message ${
                        isAssistant ? "is-assistant" : "is-user"
                      }`}
                    >
                      <div className="assistant-message-head">
                        <div className="assistant-message-speaker">
                          {speakerName}
                        </div>
                        <div className="assistant-message-time">
                          {formatTime(message.created_at)}
                        </div>
                      </div>

                      <div className="assistant-message-body">
                        {message.content ? (
                          message.content
                        ) : isAssistant ? (
                          <span className="assistant-typing">
                            <span className="assistant-typing-dot" />
                            <span className="assistant-typing-dot" />
                            <span className="assistant-typing-dot" />
                            <span className="assistant-typing-label">
                              Thinking...
                            </span>
                          </span>
                        ) : null}
                      </div>

                      {message.audio_url ? (
                        <button
                          className="assistant-audio-button"
                          type="button"
                          onClick={() => void handleAudioToggle(message.audio_url!)}
                        >
                          {playingAudioUrl === message.audio_url
                            ? "Pause Audio"
                            : "Play Audio"}
                        </button>
                      ) : null}
                    </article>
                  );
                })
              )}
            </div>

            <div className="assistant-composer">
              <label className="field-group assistant-composer-field">
                <span className="field-label">Text Chat</span>
                <textarea
                  className="assistant-textarea"
                  value={messageDraft}
                  onChange={(event) => setMessageDraft(event.target.value)}
                  placeholder="Send a text-only question in the main chat"
                  disabled={!token || isSending}
                />
              </label>

              <div className="assistant-composer-actions">
                <div className="assistant-composer-tip">
                  Main chat uses text-only replies.
                </div>
                <button
                  className="button-primary"
                  type="button"
                  onClick={handleSendMessage}
                  disabled={!token || isSending}
                >
                  {isSending ? "Sending..." : "Send Message"}
                </button>
              </div>
            </div>
          </div>
        </div>
      </div>

      <button
        className="assistant-avatar-fab"
        type="button"
        onClick={() => setIsDrawerOpen(true)}
      >
        <span className="assistant-avatar-fab-bubble">AI</span>
        <span className="assistant-avatar-fab-copy">
          <span className="assistant-avatar-fab-title">Digital Human</span>
          <span className="assistant-avatar-fab-meta">Voice + text reply</span>
        </span>
      </button>

      {isDrawerOpen ? (
        <div
          className="assistant-avatar-modal-backdrop"
          onClick={() => setIsDrawerOpen(false)}
        >
          <aside
            className="assistant-avatar-modal"
            onClick={(event) => event.stopPropagation()}
          >
            <div className="assistant-avatar-modal-head">
              <div className="assistant-avatar-modal-label">
                <div className="assistant-avatar-modal-title">Digital Human</div>
                <div className="assistant-avatar-modal-meta">
                  Avatar chat sends voice + text replies.
                </div>
              </div>

              <div className={`assistant-presence-chip is-${presence}`}>
                <span className="assistant-presence-dot" />
                <span>{statusText}</span>
              </div>
            </div>

            <div className={`assistant-avatar-modal-stage is-${presence}`}>
              <Live2DAvatar presence={presence} />
              <div className="assistant-avatar-modal-caption">
                Live2D / Haru-2 / {statusText}
              </div>
            </div>

            <div className="assistant-avatar-mini-chat">
              {recentAvatarMessages.length === 0 ? (
                <div className="assistant-avatar-mini-empty">
                  Open a conversation and ask the digital human directly.
                </div>
              ) : (
                recentAvatarMessages.map((message) => {
                  const isAssistant = message.role === "assistant";

                  return (
                    <div
                      key={message.id}
                      className={`assistant-avatar-mini-message ${
                        isAssistant ? "is-assistant" : "is-user"
                      }`}
                    >
                      <span className="assistant-avatar-mini-speaker">
                        {isAssistant ? "AI Tutor" : learnerName}
                      </span>
                      <span>
                        {message.content ? (
                          message.content
                        ) : isAssistant ? (
                          <span className="assistant-typing assistant-typing-inline">
                            <span className="assistant-typing-dot" />
                            <span className="assistant-typing-dot" />
                            <span className="assistant-typing-dot" />
                            <span className="assistant-typing-label">
                              Thinking...
                            </span>
                          </span>
                        ) : null}
                      </span>
                    </div>
                  );
                })
              )}
            </div>

            <div className="assistant-avatar-modal-foot">
              <input
                className="assistant-avatar-input"
                type="text"
                value={avatarDraft}
                onChange={(event) => setAvatarDraft(event.target.value)}
                placeholder="Ask the digital human"
                disabled={!token || isSending}
                onKeyDown={(event) => {
                  if (event.key === "Enter") {
                    event.preventDefault();
                    void handleSendAvatarMessage();
                  }
                }}
              />

              <div className="assistant-avatar-modal-actions">
                <button
                  className="button-secondary assistant-small-button"
                  type="button"
                  onClick={() => setIsDrawerOpen(false)}
                >
                  Close
                </button>
                <button
                  className="button-primary assistant-small-button"
                  type="button"
                  onClick={handleSendAvatarMessage}
                  disabled={!token || isSending}
                >
                  {isSending ? "Sending..." : "Send"}
                </button>
              </div>
            </div>
          </aside>
        </div>
      ) : null}
    </section>
  );
}
